package site.jagged.planneriti.data.local

import android.content.Context
import androidx.datastore.core.DataStore
import androidx.datastore.preferences.core.*
import androidx.datastore.preferences.preferencesDataStore
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.catch
import kotlinx.coroutines.flow.map
import site.jagged.planneriti.domain.model.UserSettings
import java.io.IOException
import javax.inject.Inject
import javax.inject.Singleton

val Context.settingsDataStore by preferencesDataStore(name = "user_settings")

@Singleton
class SettingsDataStore @Inject constructor(
    @ApplicationContext private val context: Context
) {
    private val dataStore = context.settingsDataStore

    private object Keys {
        val LANGUAGE = stringPreferencesKey("language")
        val GROUP_ID = stringPreferencesKey("selected_group_id")
        val GROUP_NAME = stringPreferencesKey("selected_group_name")
        val SUBGROUP = stringPreferencesKey("subgroup")
        val SCHEDULE_VIEW = stringPreferencesKey("schedule_view")
        val IDNP = stringPreferencesKey("idnp")
        val NOTIFICATIONS_ENABLED = booleanPreferencesKey("notifications_enabled")
        val NOTIFICATION_HOUR = intPreferencesKey("notification_hour")
        val NOTIFICATION_MINUTE = intPreferencesKey("notification_minute")
    }

    val settings: Flow<UserSettings> = dataStore.data
        .catch { if (it is IOException) emit(emptyPreferences()) else throw it }
        .map { prefs ->
            UserSettings(
                language = prefs[Keys.LANGUAGE] ?: "en",
                selectedGroupId = prefs[Keys.GROUP_ID] ?: "",
                selectedGroupName = prefs[Keys.GROUP_NAME] ?: "P-2422",
                subgroup = prefs[Keys.SUBGROUP] ?: "Subgroup 2",
                scheduleView = prefs[Keys.SCHEDULE_VIEW] ?: "day"
            )
        }

    val idnp: Flow<String?> = dataStore.data
        .map { it[Keys.IDNP] }

    val language: Flow<String> = dataStore.data
        .map { it[Keys.LANGUAGE] ?: "en" }

    suspend fun setLanguage(language: String) {
        dataStore.edit { it[Keys.LANGUAGE] = language }
    }

    suspend fun setGroup(id: String, name: String) {
        dataStore.edit {
            it[Keys.GROUP_ID] = id
            it[Keys.GROUP_NAME] = name
        }
    }

    suspend fun setSubgroup(subgroup: String) {
        dataStore.edit { it[Keys.SUBGROUP] = subgroup }
    }

    suspend fun setScheduleView(view: String) {
        dataStore.edit { it[Keys.SCHEDULE_VIEW] = view }
    }

    suspend fun saveIdnp(idnp: String) {
        dataStore.edit { it[Keys.IDNP] = idnp }
    }

    suspend fun clearIdnp() {
        dataStore.edit { it.remove(Keys.IDNP) }
    }
}

package site.jagged.planneriti.data.local

import android.content.Context
import androidx.datastore.preferences.core.*
import androidx.datastore.preferences.preferencesDataStore
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.catch
import kotlinx.coroutines.flow.map
import site.jagged.planneriti.domain.model.UserSettings
import site.jagged.planneriti.ui.settings.CustomPeriodSetting
import site.jagged.planneriti.ui.settings.NotificationSettings
import java.io.IOException
import javax.inject.Inject
import javax.inject.Singleton

val Context.settingsDataStore by preferencesDataStore(name = "user_settings")

@Singleton
class SettingsDataStore @Inject constructor(
    @ApplicationContext private val context: Context
) {
    private val dataStore = context.settingsDataStore
    private val gson = Gson()

    private object Keys {
        val LANGUAGE = stringPreferencesKey("language")
        val GROUP_ID = stringPreferencesKey("selected_group_id")
        val GROUP_NAME = stringPreferencesKey("selected_group_name")
        val SUBGROUP = stringPreferencesKey("subgroup")
        val SCHEDULE_VIEW = stringPreferencesKey("schedule_view")
        val IDNP = stringPreferencesKey("idnp")
        val NOTIFICATIONS_ENABLED = booleanPreferencesKey("notifications_enabled")
        val NOTIFICATION_HOUR = intPreferencesKey("notification_hour")
        val NOTIFICATION_MINUTE = intPreferencesKey("notification_minute")
        val EXAM_REMINDER_DAYS = intPreferencesKey("exam_reminder_days")
        val TEST_REMINDER_DAYS = intPreferencesKey("test_reminder_days")
        val QUIZ_REMINDER_DAYS = intPreferencesKey("quiz_reminder_days")
        val PROJECT_REMINDER_DAYS = intPreferencesKey("project_reminder_days")
        val HOMEWORK_REMINDER_DAYS = intPreferencesKey("homework_reminder_days")
        val OTHER_REMINDER_DAYS = intPreferencesKey("other_reminder_days")
        val DAILY_EXAMS = booleanPreferencesKey("daily_exams")
        val DAILY_TESTS = booleanPreferencesKey("daily_tests")
        val DAILY_QUIZZES = booleanPreferencesKey("daily_quizzes")
        val CUSTOM_PERIODS_JSON = stringPreferencesKey("custom_periods_json")
        val LAST_SCHEDULE_REFRESH = longPreferencesKey("last_schedule_refresh")
        val DISMISSED_UPDATE_VERSION = stringPreferencesKey("dismissed_update_version")
        val DISMISSED_UPDATE_UNTIL = longPreferencesKey("dismissed_update_until")
        val LAST_UPDATE_CHECK = longPreferencesKey("last_update_check")
    }

    val settings: Flow<UserSettings> = dataStore.data
        .catch { if (it is IOException) emit(emptyPreferences()) else throw it }
        .map { prefs ->
            UserSettings(
                language = prefs[Keys.LANGUAGE] ?: "en",
                selectedGroupId = prefs[Keys.GROUP_ID] ?: "",
                selectedGroupName = prefs[Keys.GROUP_NAME] ?: "P-2422",
                subgroup = prefs[Keys.SUBGROUP] ?: "Subgroup 2",
                scheduleView = prefs[Keys.SCHEDULE_VIEW] ?: "day"
            )
        }

    val idnp: Flow<String?> = dataStore.data
        .map { it[Keys.IDNP] }

    val customPeriods: Flow<List<CustomPeriodSetting>> = dataStore.data.map { prefs ->
        val raw = prefs[Keys.CUSTOM_PERIODS_JSON] ?: "[]"
        runCatching {
            val type = object : TypeToken<List<CustomPeriodSetting>>() {}.type
            gson.fromJson<List<CustomPeriodSetting>>(raw, type) ?: emptyList()
        }.getOrDefault(emptyList<CustomPeriodSetting>())
    }

    val notificationSettings: Flow<NotificationSettings> = dataStore.data.map { prefs ->
        NotificationSettings(
            enabled = prefs[Keys.NOTIFICATIONS_ENABLED] ?: true,
            notificationHour = prefs[Keys.NOTIFICATION_HOUR] ?: 18,
            notificationMinute = prefs[Keys.NOTIFICATION_MINUTE] ?: 0,
            examReminderDays = prefs[Keys.EXAM_REMINDER_DAYS] ?: 3,
            testReminderDays = prefs[Keys.TEST_REMINDER_DAYS] ?: 2,
            quizReminderDays = prefs[Keys.QUIZ_REMINDER_DAYS] ?: 1,
            projectReminderDays = prefs[Keys.PROJECT_REMINDER_DAYS] ?: 4,
            homeworkReminderDays = prefs[Keys.HOMEWORK_REMINDER_DAYS] ?: 1,
            otherReminderDays = prefs[Keys.OTHER_REMINDER_DAYS] ?: 1,
            dailyRemindersForExams = prefs[Keys.DAILY_EXAMS] ?: true,
            dailyRemindersForTests = prefs[Keys.DAILY_TESTS] ?: true,
            dailyRemindersForQuizzes = prefs[Keys.DAILY_QUIZZES] ?: true
        )
    }

    val lastScheduleRefreshEpoch: Flow<Long?> = dataStore.data.map { it[Keys.LAST_SCHEDULE_REFRESH] }

    val dismissedUpdateVersion: Flow<String?> = dataStore.data.map { it[Keys.DISMISSED_UPDATE_VERSION] }
    val dismissedUpdateUntilEpoch: Flow<Long?> = dataStore.data.map { it[Keys.DISMISSED_UPDATE_UNTIL] }
    val lastUpdateCheckEpoch: Flow<Long?> = dataStore.data.map { it[Keys.LAST_UPDATE_CHECK] }

    val language: Flow<String> = dataStore.data
        .map { it[Keys.LANGUAGE] ?: "en" }

    suspend fun setLanguage(language: String) {
        dataStore.edit { it[Keys.LANGUAGE] = language }
    }

    suspend fun setGroup(id: String, name: String) {
        dataStore.edit {
            it[Keys.GROUP_ID] = id
            it[Keys.GROUP_NAME] = name
        }
    }

    suspend fun setSubgroup(subgroup: String) {
        dataStore.edit { it[Keys.SUBGROUP] = subgroup }
    }

    suspend fun setScheduleView(view: String) {
        dataStore.edit { it[Keys.SCHEDULE_VIEW] = view }
    }

    suspend fun saveIdnp(idnp: String) {
        dataStore.edit { it[Keys.IDNP] = idnp }
    }

    suspend fun clearIdnp() {
        dataStore.edit { it.remove(Keys.IDNP) }
    }

    suspend fun setCustomPeriods(periods: List<CustomPeriodSetting>) {
        dataStore.edit { it[Keys.CUSTOM_PERIODS_JSON] = gson.toJson(periods) }
    }

    suspend fun saveNotificationSettings(settings: NotificationSettings) {
        dataStore.edit {
            it[Keys.NOTIFICATIONS_ENABLED] = settings.enabled
            it[Keys.NOTIFICATION_HOUR] = settings.notificationHour
            it[Keys.NOTIFICATION_MINUTE] = settings.notificationMinute
            it[Keys.EXAM_REMINDER_DAYS] = settings.examReminderDays
            it[Keys.TEST_REMINDER_DAYS] = settings.testReminderDays
            it[Keys.QUIZ_REMINDER_DAYS] = settings.quizReminderDays
            it[Keys.PROJECT_REMINDER_DAYS] = settings.projectReminderDays
            it[Keys.HOMEWORK_REMINDER_DAYS] = settings.homeworkReminderDays
            it[Keys.OTHER_REMINDER_DAYS] = settings.otherReminderDays
            it[Keys.DAILY_EXAMS] = settings.dailyRemindersForExams
            it[Keys.DAILY_TESTS] = settings.dailyRemindersForTests
            it[Keys.DAILY_QUIZZES] = settings.dailyRemindersForQuizzes
        }
    }

    suspend fun setLastScheduleRefresh(epochMillis: Long) {
        dataStore.edit { it[Keys.LAST_SCHEDULE_REFRESH] = epochMillis }
    }

    suspend fun clearLastScheduleRefresh() {
        dataStore.edit { it.remove(Keys.LAST_SCHEDULE_REFRESH) }
    }

    suspend fun setUpdateDismissed(version: String, untilEpochMillis: Long) {
        dataStore.edit {
            it[Keys.DISMISSED_UPDATE_VERSION] = version
            it[Keys.DISMISSED_UPDATE_UNTIL] = untilEpochMillis
        }
    }

    suspend fun clearUpdateDismissed() {
        dataStore.edit {
            it.remove(Keys.DISMISSED_UPDATE_VERSION)
            it.remove(Keys.DISMISSED_UPDATE_UNTIL)
        }
    }

    suspend fun setLastUpdateCheck(epochMillis: Long) {
        dataStore.edit { it[Keys.LAST_UPDATE_CHECK] = epochMillis }
    }
}

package site.jagged.planneriti.data.remote.api

import retrofit2.http.Body
import retrofit2.http.GET
import retrofit2.http.POST

data class LoginRequest(val email: String, val password: String)
data class LoginResponse(val accessToken: String)
data class SignupRequest(val email: String, val password: String, val confirmPassword: String)
data class UserResponse(val email: String, val isVerified: Boolean)
data class ForgotPasswordRequest(val email: String)

interface AuthApi {
    @POST("auth/login")
    suspend fun login(@Body request: LoginRequest): LoginResponse

    @POST("auth/signup")
    suspend fun signup(@Body request: SignupRequest): Map<String, String>

    @GET("auth/me")
    suspend fun getMe(): UserResponse

    @POST("auth/forgot-password")
    suspend fun forgotPassword(@Body request: ForgotPasswordRequest)
}

package site.jagged.planneriti.data.remote.api

import com.google.gson.annotations.SerializedName
import retrofit2.http.Body
import retrofit2.http.GET
import retrofit2.http.POST

data class LoginRequest(val email: String, val password: String)
data class LoginResponse(
    @SerializedName("access_token") val accessToken: String
)
data class SignupRequest(
    val email: String,
    val password: String,
    @SerializedName("confirm_password") val confirmPassword: String
)
data class UserResponse(
    val email: String,
    @SerializedName("is_verified") val isVerified: Boolean
)
data class ForgotPasswordRequest(val email: String)
data class DeleteAccountRequest(val password: String)

interface AuthApi {
    @POST("auth/login")
    suspend fun login(@Body request: LoginRequest): LoginResponse

    @POST("auth/signup")
    suspend fun signup(@Body request: SignupRequest): Map<String, String>

    @GET("auth/me")
    suspend fun getMe(): UserResponse

    @POST("auth/forgot-password")
    suspend fun forgotPassword(@Body request: ForgotPasswordRequest)

    @POST("auth/delete-account/initiate")
    suspend fun deleteAccount(@Body request: DeleteAccountRequest)
}

package site.jagged.planneriti.data.repository

import site.jagged.planneriti.data.local.SecureStorage
import site.jagged.planneriti.data.remote.api.AuthApi
import site.jagged.planneriti.data.remote.api.ForgotPasswordRequest
import site.jagged.planneriti.data.remote.api.LoginRequest
import site.jagged.planneriti.data.remote.api.SignupRequest
//import site.jagged.planneriti.domain.model.User
import javax.inject.Inject
import javax.inject.Singleton

data class User(val email: String, val isVerified: Boolean)

@Singleton
class AuthRepository @Inject constructor(
    private val api: AuthApi,
    private val secureStorage: SecureStorage
) {
    fun isLoggedIn(): Boolean = secureStorage.getAuthToken() != null

    suspend fun login(email: String, password: String): Result<User> {
        return try {
            val response = api.login(LoginRequest(email, password))
            secureStorage.saveAuthToken(response.accessToken)
            secureStorage.saveCredentials(email, password)
            val user = api.getMe()
            Result.success(User(user.email, user.isVerified))
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    suspend fun signup(email: String, password: String, confirmPassword: String): Result<Unit> {
        return try {
            api.signup(SignupRequest(email, password, confirmPassword))
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    suspend fun getCurrentUser(): User? {
        return try {
            if (!isLoggedIn()) return null
            val user = api.getMe()
            User(user.email, user.isVerified)
        } catch (e: Exception) {
            null
        }
    }

    suspend fun forgotPassword(email: String): Result<Unit> {
        return try {
            api.forgotPassword(ForgotPasswordRequest(email))
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    fun logout() {
        secureStorage.clearAuthToken()
        secureStorage.clearCredentials()
    }
}

package site.jagged.planneriti.data.repository

import site.jagged.planneriti.data.local.SecureStorage
import site.jagged.planneriti.data.remote.api.AuthApi
import site.jagged.planneriti.data.remote.api.DeleteAccountRequest
import site.jagged.planneriti.data.remote.api.ForgotPasswordRequest
import site.jagged.planneriti.data.remote.api.LoginRequest
import site.jagged.planneriti.data.remote.api.SignupRequest
//import site.jagged.planneriti.domain.model.User
import javax.inject.Inject
import javax.inject.Singleton

data class User(val email: String, val isVerified: Boolean)

@Singleton
class AuthRepository @Inject constructor(
    private val api: AuthApi,
    private val secureStorage: SecureStorage
) {
    fun isLoggedIn(): Boolean = secureStorage.getAuthToken() != null

    suspend fun login(email: String, password: String): Result<User> {
        return try {
            val response = api.login(LoginRequest(email, password))
            secureStorage.saveAuthToken(response.accessToken)
            secureStorage.saveCredentials(email, password)
            val user = api.getMe()
            Result.success(User(user.email, user.isVerified))
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    suspend fun signup(email: String, password: String, confirmPassword: String): Result<Unit> {
        return try {
            api.signup(SignupRequest(email, password, confirmPassword))
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    suspend fun getCurrentUser(): User? {
        return try {
            if (!isLoggedIn()) return null
            val user = api.getMe()
            User(user.email, user.isVerified)
        } catch (e: Exception) {
            null
        }
    }

    suspend fun refreshCurrentUser(): Result<User> {
        return try {
            if (!isLoggedIn()) {
                Result.failure(IllegalStateException("User is not logged in"))
            } else {
                val user = api.getMe()
                Result.success(User(user.email, user.isVerified))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    suspend fun forgotPassword(email: String): Result<Unit> {
        return try {
            api.forgotPassword(ForgotPasswordRequest(email))
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    suspend fun deleteAccount(password: String): Result<Unit> {
        return try {
            api.deleteAccount(DeleteAccountRequest(password))
            logout()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    fun logout() {
        secureStorage.clearAuthToken()
        secureStorage.clearCredentials()
    }
}

package site.jagged.planneriti.data.repository

import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.firstOrNull
import site.jagged.planneriti.data.local.SettingsDataStore
import site.jagged.planneriti.data.remote.api.ScheduleApi
import site.jagged.planneriti.ui.settings.CustomPeriodSetting
import site.jagged.planneriti.ui.settings.GroupOption
import site.jagged.planneriti.ui.settings.NotificationSettings
import javax.inject.Inject
import javax.inject.Singleton

@Singleton
class SettingsRepository @Inject constructor(
    private val settingsDataStore: SettingsDataStore,
    private val scheduleApi: ScheduleApi
) {
    private var cachedGroups: List<GroupOption> = emptyList()

    val settings = settingsDataStore.settings
    val customPeriods = settingsDataStore.customPeriods
    val idnp = settingsDataStore.idnp
    val notificationSettings = settingsDataStore.notificationSettings
    val lastScheduleRefreshEpoch = settingsDataStore.lastScheduleRefreshEpoch

    suspend fun getGroups(forceRefresh: Boolean = false): List<GroupOption> {
        if (!forceRefresh && cachedGroups.isNotEmpty()) return cachedGroups

        val groups = scheduleApi.getGroups().map {
            GroupOption(
                id = it.id,
                name = it.name,
                teacherName = it.diriginte?.name
            )
        }
        cachedGroups = groups
        return groups
    }

    suspend fun setLanguage(language: String) = settingsDataStore.setLanguage(language)

    suspend fun setSubgroup(subgroup: String) = settingsDataStore.setSubgroup(subgroup)

    suspend fun setScheduleView(view: String) = settingsDataStore.setScheduleView(view)

    suspend fun setGroup(groupId: String, groupName: String) {
        settingsDataStore.setGroup(groupId, groupName)
        settingsDataStore.setLastScheduleRefresh(System.currentTimeMillis())
    }

    suspend fun saveIdnp(idnp: String) = settingsDataStore.saveIdnp(idnp)

    suspend fun clearIdnp() = settingsDataStore.clearIdnp()

    suspend fun setNotificationSettings(settings: NotificationSettings) {
        settingsDataStore.saveNotificationSettings(settings)
    }

    suspend fun addCustomPeriod(period: CustomPeriodSetting) {
        val current = customPeriods.firstOrNull().orEmpty()
        settingsDataStore.setCustomPeriods(current + period)
    }

    suspend fun updateCustomPeriod(period: CustomPeriodSetting) {
        val current = customPeriods.firstOrNull().orEmpty()
        val updated = current.map { if (it.id == period.id) period else it }
        settingsDataStore.setCustomPeriods(updated)
    }

    suspend fun deleteCustomPeriod(id: String) {
        val current = customPeriods.firstOrNull().orEmpty()
        settingsDataStore.setCustomPeriods(current.filterNot { it.id == id })
    }

    suspend fun refreshScheduleMetadata() {
        settingsDataStore.setLastScheduleRefresh(System.currentTimeMillis())
    }

    suspend fun clearScheduleCache() {
        settingsDataStore.clearLastScheduleRefresh()
    }

    suspend fun resetSettingsToDefaults() {
        settingsDataStore.setLanguage("en")
        settingsDataStore.setSubgroup("Subgroup 2")
        settingsDataStore.setScheduleView("day")
        settingsDataStore.setCustomPeriods(emptyList())
        settingsDataStore.saveNotificationSettings(NotificationSettings())
        settingsDataStore.clearLastScheduleRefresh()
    }

    fun lastUpdateCheckEpoch(): Flow<Long?> = settingsDataStore.lastUpdateCheckEpoch
    fun dismissedUpdateVersion(): Flow<String?> = settingsDataStore.dismissedUpdateVersion
    fun dismissedUpdateUntilEpoch(): Flow<Long?> = settingsDataStore.dismissedUpdateUntilEpoch

    suspend fun setUpdateDismissed(version: String, untilEpochMillis: Long) {
        settingsDataStore.setUpdateDismissed(version, untilEpochMillis)
    }

    suspend fun clearUpdateDismissed() = settingsDataStore.clearUpdateDismissed()

    suspend fun setLastUpdateCheck(epochMillis: Long) = settingsDataStore.setLastUpdateCheck(epochMillis)
}

package site.jagged.planneriti.data.repository

import android.content.Context
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.flow.firstOrNull
import okhttp3.OkHttpClient
import okhttp3.Request
import site.jagged.planneriti.ui.settings.UpdateInfo
import javax.inject.Inject
import javax.inject.Singleton

private data class GithubRelease(
    val tag_name: String,
    val body: String?,
    val html_url: String,
    val published_at: String,
    val prerelease: Boolean
)

@Singleton
class UpdateRepository @Inject constructor(
    @ApplicationContext private val context: Context,
    private val okHttpClient: OkHttpClient,
    private val settingsRepository: SettingsRepository
) {
    private val gson = Gson()

    private val githubReleasesUrl = "https://api.github.com/repos/JaggedGem/PlannerITI/releases"
    private val remindLaterDays = 7

    suspend fun checkForUpdate(forceCheck: Boolean = false): UpdateInfo? {
        if (!forceCheck && !shouldCheckToday()) return null

        settingsRepository.setLastUpdateCheck(System.currentTimeMillis())
        val release = fetchLatestRelease(productionOnly = true) ?: return null

        val latestVersion = release.tag_name
        if (compareVersions(getCurrentVersion(), latestVersion) >= 0) return null

        if (!forceCheck && isVersionDismissed(latestVersion)) return null

        return UpdateInfo(
            isAvailable = true,
            currentVersion = getCurrentVersion(),
            latestVersion = latestVersion,
            releaseNotes = release.body ?: "No release notes available.",
            releaseUrl = release.html_url,
            publishedAt = release.published_at
        )
    }

    suspend fun manualCheckForUpdate(): UpdateInfo? {
        clearDismissedVersion()
        return checkForUpdate(forceCheck = true)
    }

    suspend fun dismissVersion(version: String) {
        val until = System.currentTimeMillis() + remindLaterDays * 24L * 60L * 60L * 1000L
        settingsRepository.setUpdateDismissed(version, until)
    }

    suspend fun clearDismissedVersion() = settingsRepository.clearUpdateDismissed()

    fun getCurrentVersion(): String {
        return runCatching {
            context.packageManager.getPackageInfo(context.packageName, 0).versionName ?: "1.0"
        }.getOrDefault("1.0")
    }

    private suspend fun shouldCheckToday(): Boolean {
        val now = System.currentTimeMillis()
        val last = settingsRepository.lastUpdateCheckEpoch().firstOrNull() ?: return true
        val dayMillis = 24L * 60L * 60L * 1000L
        return now - last >= dayMillis
    }

    private suspend fun isVersionDismissed(version: String): Boolean {
        val dismissedVersion = settingsRepository.dismissedUpdateVersion().firstOrNull() ?: return false
        val dismissedUntil = settingsRepository.dismissedUpdateUntilEpoch().firstOrNull() ?: return false
        return dismissedVersion == version && dismissedUntil > System.currentTimeMillis()
    }

    private fun compareVersions(current: String, latest: String): Int {
        fun normalize(v: String) = v.removePrefix("v").split("-").first()
        val c = normalize(current).split(".").map { it.toIntOrNull() ?: 0 }
        val l = normalize(latest).split(".").map { it.toIntOrNull() ?: 0 }
        val max = maxOf(c.size, l.size)
        for (i in 0 until max) {
            val cv = c.getOrElse(i) { 0 }
            val lv = l.getOrElse(i) { 0 }
            if (cv != lv) return cv.compareTo(lv)
        }
        return 0
    }

    private fun fetchLatestRelease(productionOnly: Boolean): GithubRelease? {
        return runCatching {
            val request = Request.Builder()
                .url(githubReleasesUrl)
                .header("Accept", "application/vnd.github+json")
                .build()
            okHttpClient.newCall(request).execute().use { response ->
                if (!response.isSuccessful) return null
                val body = response.body.string()
                if (body.isBlank()) return null
                val listType = object : TypeToken<List<GithubRelease>>() {}.type
                val releases: List<GithubRelease> = gson.fromJson(body, listType)
                val filtered = if (productionOnly) releases.filter { !it.prerelease } else releases
                filtered.firstOrNull()
            }
        }.getOrNull()
    }
}

package site.jagged.planneriti.di

import dagger.Module
import dagger.Provides
import dagger.hilt.InstallIn
import dagger.hilt.components.SingletonComponent
import site.jagged.planneriti.data.remote.api.GradesApi
import site.jagged.planneriti.data.remote.api.PapiApi
import site.jagged.planneriti.data.remote.api.ScheduleApi
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import site.jagged.planneriti.data.remote.api.AuthApi
import java.util.concurrent.TimeUnit
import javax.inject.Singleton

@Module
@InstallIn(SingletonComponent::class)
object NetworkModule {

    @Provides
    @Singleton
    fun provideOkHttpClient(): OkHttpClient {
        return OkHttpClient.Builder()
            .addInterceptor(
                HttpLoggingInterceptor().apply {
                    level = HttpLoggingInterceptor.Level.BODY
                }
            )
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .build()
    }

    @Provides
    @Singleton
    fun provideScheduleApi(okHttpClient: OkHttpClient): ScheduleApi {
        return Retrofit.Builder()
            .baseUrl("https://orar-api.ceiti.md/")
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(ScheduleApi::class.java)
    }

    @Provides
    @Singleton
    fun provideGradesApi(okHttpClient: OkHttpClient): GradesApi {
        return Retrofit.Builder()
            .baseUrl("https://api.ceiti.md/")
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(GradesApi::class.java)
    }

    @Provides
    @Singleton
    fun providePapiApi(okHttpClient: OkHttpClient): PapiApi {
        return Retrofit.Builder()
            .baseUrl("https://papi.jagged.site/")
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(PapiApi::class.java)
    }

    @Provides
    @Singleton
    fun provideAuthApi(okHttpClient: OkHttpClient): AuthApi {
        // needs auth header injected — we'll add an interceptor
        val authOkHttpClient = okHttpClient.newBuilder()
            .addInterceptor { chain ->
                val token = "" // we'll fix this with proper auth state
                val request = chain.request().newBuilder()
                    .apply { if (token.isNotEmpty()) addHeader("Authorization", "Bearer $token") }
                    .build()
                chain.proceed(request)
            }
            .build()

        return Retrofit.Builder()
            .baseUrl("https://papi.jagged.site/")
            .client(authOkHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(AuthApi::class.java)
    }
}

package site.jagged.planneriti.di

import dagger.Module
import dagger.Provides
import dagger.hilt.InstallIn
import dagger.hilt.components.SingletonComponent
import site.jagged.planneriti.data.remote.api.GradesApi
import site.jagged.planneriti.data.remote.api.PapiApi
import site.jagged.planneriti.data.remote.api.ScheduleApi
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import site.jagged.planneriti.data.remote.api.AuthApi
import site.jagged.planneriti.data.local.SecureStorage
import java.util.concurrent.TimeUnit
import javax.inject.Singleton

@Module
@InstallIn(SingletonComponent::class)
object NetworkModule {

    @Provides
    @Singleton
    fun provideOkHttpClient(): OkHttpClient {
        return OkHttpClient.Builder()
            .addInterceptor(
                HttpLoggingInterceptor().apply {
                    level = HttpLoggingInterceptor.Level.BODY
                }
            )
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .build()
    }

    @Provides
    @Singleton
    fun provideScheduleApi(okHttpClient: OkHttpClient): ScheduleApi {
        return Retrofit.Builder()
            .baseUrl("https://orar-api.ceiti.md/")
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(ScheduleApi::class.java)
    }

    @Provides
    @Singleton
    fun provideGradesApi(okHttpClient: OkHttpClient): GradesApi {
        return Retrofit.Builder()
            .baseUrl("https://api.ceiti.md/")
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(GradesApi::class.java)
    }

    @Provides
    @Singleton
    fun providePapiApi(okHttpClient: OkHttpClient): PapiApi {
        return Retrofit.Builder()
            .baseUrl("https://papi.jagged.site/")
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(PapiApi::class.java)
    }

    @Provides
    @Singleton
    fun provideAuthApi(
        okHttpClient: OkHttpClient,
        secureStorage: SecureStorage
    ): AuthApi {
        val authOkHttpClient = okHttpClient.newBuilder()
            .addInterceptor { chain ->
                val token = secureStorage.getAuthToken().orEmpty()
                val request = chain.request().newBuilder()
                    .apply { if (token.isNotEmpty()) addHeader("Authorization", "Bearer $token") }
                    .build()
                chain.proceed(request)
            }
            .build()

        return Retrofit.Builder()
            .baseUrl("https://papi.jagged.site/")
            .client(authOkHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(AuthApi::class.java)
    }
}

