@Composable
private fun ScheduleCard(
    uiState: SettingsUiState,
    onGroupClick: () -> Unit,
    onSubgroupSelect: (String) -> Unit,
    onRefresh: () -> Unit,
    onClearCache: () -> Unit
) {
    AppCard {
        AppSectionTitle("Schedule")
        SettingRow(title = "Group", value = uiState.selectedGroupName, onClick = onGroupClick)
        AppDivider()
        Text("Subgroup", color = Color.White, fontWeight = FontWeight.SemiBold)
        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
            FilterChip(
                selected = uiState.subgroup == "Subgroup 1",
                onClick = { onSubgroupSelect("Subgroup 1") },
                label = { Text("Subgroup 1") }
            )
            FilterChip(
                selected = uiState.subgroup == "Subgroup 2",
                onClick = { onSubgroupSelect("Subgroup 2") },
                label = { Text("Subgroup 2") }
            )
        }
        AppDivider()
        Text(
            "Last refresh: ${uiState.lastScheduleRefreshEpoch?.let(::formatDateTime) ?: "never"}",
            color = OnSurfaceMuted
        )
        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
            Button(onClick = onRefresh, enabled = !uiState.isRefreshingSchedule) {
                Text(if (uiState.isRefreshingSchedule) "Refreshing..." else "Refresh")
            }
            OutlinedButton(onClick = onClearCache) { Text("Clear Cache") }
        }
    }
}

@Composable
private fun UpdateCard(
    uiState: SettingsUiState,
    onCheckNow: () -> Unit,
    onRemindLater: (String) -> Unit
) {
    AppCard {
        AppSectionTitle("App Updates")
        SettingRow(
            title = "Current version",
            value = uiState.currentVersion,
            subtitle = "Checks once per day automatically"
        )
        Button(onClick = onCheckNow, enabled = !uiState.isCheckingForUpdate) {
            Text(if (uiState.isCheckingForUpdate) "Checking..." else "Check now")
        }
        uiState.updateInfo?.let { update ->
            Text("New version ${update.latestVersion} available", color = Color(0xFF30D158), fontWeight = FontWeight.SemiBold)
            Text(update.releaseNotes, color = OnSurfaceMuted, maxLines = 4, overflow = TextOverflow.Ellipsis)
            OutlinedButton(onClick = { onRemindLater(update.latestVersion) }) { Text("Remind me later") }
        }
        uiState.updateMessage?.let { Text(it, color = OnSurfaceMuted) }
    }
}

@Composable
private fun NotificationCard(uiState: SettingsUiState, onSave: (NotificationSettings) -> Unit) {
    AppCard {
        AppSectionTitle("Notifications")
        Row(verticalAlignment = Alignment.CenterVertically) {
            Text("Enable reminders", color = Color.White, modifier = Modifier.weight(1f))
            Switch(
                checked = uiState.notificationSettings.enabled,
                onCheckedChange = { onSave(uiState.notificationSettings.copy(enabled = it)) }
            )
        }
        if (uiState.notificationSettings.enabled) {
            ReminderRow(
                label = "Exams",
                value = uiState.notificationSettings.examReminderDays,
                onChange = { onSave(uiState.notificationSettings.copy(examReminderDays = it)) }
            )
            ReminderRow(
                label = "Tests",
                value = uiState.notificationSettings.testReminderDays,
                onChange = { onSave(uiState.notificationSettings.copy(testReminderDays = it)) }
            )
            ReminderRow(
                label = "Quizzes",
                value = uiState.notificationSettings.quizReminderDays,
                onChange = { onSave(uiState.notificationSettings.copy(quizReminderDays = it)) }
            )
            ReminderRow(
                label = "Projects",
                value = uiState.notificationSettings.projectReminderDays,
                onChange = { onSave(uiState.notificationSettings.copy(projectReminderDays = it)) }
            )
        }
    }
}

@Composable
private fun CustomPeriodsCard(
    periods: List<CustomPeriodSetting>,
    onAdd: () -> Unit,
    onEdit: (CustomPeriodSetting) -> Unit,
    onDelete: (String) -> Unit,
    onToggle: (CustomPeriodSetting, Boolean) -> Unit
) {
    AppCard {
        Row(verticalAlignment = Alignment.CenterVertically) {
            AppSectionTitle("Custom Periods", "Add personal time blocks")
            Spacer(Modifier.weight(1f))
            IconButton(onClick = onAdd) {
                Icon(Icons.Default.Add, contentDescription = "Add custom period", tint = Color.White)
            }
        }
        if (periods.isEmpty()) {
            Text("No custom periods configured.", color = OnSurfaceMuted)
        } else {
            periods.forEach { period ->
                AppDivider()
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Box(
                        modifier = Modifier
                            .size(10.dp)
                            .background(Color(android.graphics.Color.parseColor(period.colorHex)), CircleShape)
                    )
                    Spacer(Modifier.width(8.dp))
                    Column(modifier = Modifier.weight(1f)) {
                        Text(period.name, color = Color.White)
                        Text("${period.startTime} - ${period.endTime}", color = OnSurfaceMuted)
                    }
                    Switch(checked = period.isEnabled, onCheckedChange = { onToggle(period, it) })
                    IconButton(onClick = { onEdit(period) }) {
                        Icon(Icons.Default.Edit, contentDescription = "Edit period", tint = Color.White)
                    }
                    IconButton(onClick = { onDelete(period.id) }) {
                        Icon(Icons.Default.Delete, contentDescription = "Delete period", tint = Color(0xFFFF7A7A))
                    }
                }
            }
        }
    }
}

@Composable
private fun ReminderRow(label: String, value: Int, onChange: (Int) -> Unit) {
    SettingRow(
        title = label,
        value = "$value day(s)",
        trailing = {
            Row(horizontalArrangement = Arrangement.spacedBy(4.dp), verticalAlignment = Alignment.CenterVertically) {
                TextButton(onClick = { if (value > 1) onChange(value - 1) }) { Text("-") }
                TextButton(onClick = { onChange(value + 1) }) { Text("+") }
            }
        }
    )
}

@Composable
private fun ErrorBanner(message: String) {
    AppCard {
        Text(message, color = Color(0xFFFFB3B3), fontWeight = FontWeight.SemiBold)
    }
}

@Composable
private fun <T> OptionPickerDialog(
    title: String,
    options: List<T>,
    selectedId: String,
    id: (T) -> String,
    label: (T) -> String,
    supportingText: (T) -> String?,
    onDismiss: () -> Unit,
    onSelect: (T) -> Unit
) {
    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(title) },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                options.forEach { option ->
                    val isSelected = id(option) == selectedId

                    OutlinedButton(
                        modifier = Modifier.fillMaxWidth(),
                        onClick = { onSelect(option) }
                    ) {
                        Column(modifier = Modifier.fillMaxWidth()) {
                            Text(label(option), color = if (isSelected) Primary else Color.White)
                            supportingText(option)?.let { Text(it, color = OnSurfaceMuted) }
                        }
                    }
                }
            }
        },
        confirmButton = { TextButton(onClick = onDismiss) { Text("Close") } }
    )
}

@Composable
private fun CustomPeriodDialog(
    initial: CustomPeriodSetting?,
    onDismiss: () -> Unit,
    onSave: (CustomPeriodSetting) -> Unit
) {
    var name by remember(initial) { mutableStateOf(initial?.name.orEmpty()) }
    var start by remember(initial) { mutableStateOf(initial?.startTime ?: "08:00") }
    var end by remember(initial) { mutableStateOf(initial?.endTime ?: "08:45") }
    var days by remember(initial) { mutableStateOf(initial?.daysOfWeek?.joinToString(",").orEmpty()) }
    var color by remember(initial) { mutableStateOf(initial?.colorHex ?: "#2C3DCD") }
    var enabled by remember(initial) { mutableStateOf(initial?.isEnabled ?: true) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(if (initial == null) "Add custom period" else "Edit custom period") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(value = name, onValueChange = { name = it }, label = { Text("Name") }, singleLine = true)
                OutlinedTextField(value = start, onValueChange = { start = it }, label = { Text("Start (HH:mm)") }, singleLine = true)
                OutlinedTextField(value = end, onValueChange = { end = it }, label = { Text("End (HH:mm)") }, singleLine = true)
                OutlinedTextField(value = days, onValueChange = { days = it }, label = { Text("Days (1,2,3...)") }, singleLine = true)
                OutlinedTextField(value = color, onValueChange = { color = it }, label = { Text("Color (#RRGGBB)") }, singleLine = true)
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Text("Enabled", modifier = Modifier.weight(1f))
                    Switch(checked = enabled, onCheckedChange = { enabled = it })
                }
            }
        },
        confirmButton = {
            TextButton(onClick = {
                val parsedDays = days.split(',').mapNotNull { it.trim().toIntOrNull() }.filter { it in 1..7 }
                onSave(
                    CustomPeriodSetting(
                        id = initial?.id ?: UUID.randomUUID().toString(),
                        name = name.ifBlank { "Custom Period" },
                        startTime = start,
                        endTime = end,
                        daysOfWeek = parsedDays,
                        colorHex = if (color.startsWith("#")) color else "#2C3DCD",
                        isEnabled = enabled
                    )
                )
            }) { Text("Save") }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel") } }
    )
}

private fun languageLabel(language: String): String = when (language) {
    "ro" -> "Romanian"
    "ru" -> "Russian"
    else -> "English"
}

private fun maskIdnp(idnp: String?): String {
    if (idnp.isNullOrBlank()) return "Not set"
    if (idnp.length < 8) return "Saved"
    return "${idnp.take(4)}••••••${idnp.takeLast(3)}"
}

private fun formatDateTime(epochMillis: Long): String {
    return runCatching {
        SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.getDefault()).format(Date(epochMillis))
    }.getOrDefault("-")
}

package site.jagged.planneriti.ui.settings

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import site.jagged.planneriti.data.local.SettingsDataStore
import site.jagged.planneriti.domain.model.UserSettings
import javax.inject.Inject

@HiltViewModel
class SettingsViewModel @Inject constructor(
    private val settingsDataStore: SettingsDataStore
) : ViewModel() {

    val settings: StateFlow<UserSettings> = settingsDataStore.settings
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), UserSettings())

    fun setLanguage(language: String) {
        viewModelScope.launch { settingsDataStore.setLanguage(language) }
    }

    fun setSubgroup(subgroup: String) {
        viewModelScope.launch { settingsDataStore.setSubgroup(subgroup) }
    }

    fun setScheduleView(view: String) {
        viewModelScope.launch { settingsDataStore.setScheduleView(view) }
    }
}

package site.jagged.planneriti.ui.settings

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import site.jagged.planneriti.data.repository.AuthRepository
import site.jagged.planneriti.data.repository.SettingsRepository
import site.jagged.planneriti.data.repository.UpdateRepository
import javax.inject.Inject

@HiltViewModel
class SettingsViewModel @Inject constructor(
    private val settingsRepository: SettingsRepository,
    private val authRepository: AuthRepository,
    private val updateRepository: UpdateRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow(SettingsUiState())
    val uiState: StateFlow<SettingsUiState> = _uiState.asStateFlow()

    val settings = settingsRepository.settings
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), site.jagged.planneriti.domain.model.UserSettings())

    init {
        _uiState.update { it.copy(currentVersion = updateRepository.getCurrentVersion()) }
        observeSettings()
        refreshAccount()
        loadGroups()
    }

    private fun observeSettings() {
        viewModelScope.launch {
            combine(
                settingsRepository.settings,
                settingsRepository.customPeriods,
                settingsRepository.idnp,
                settingsRepository.notificationSettings,
                settingsRepository.lastScheduleRefreshEpoch
            ) { settings, periods, idnp, notifications, lastRefresh ->
                settings to periods to idnp to notifications to lastRefresh
            }.collect { chain ->
                val settings = chain.first.first.first.first
                val periods = chain.first.first.first.second
                val idnp = chain.first.first.second
                val notifications = chain.first.second
                val lastRefresh = chain.second

                _uiState.update {
                    it.copy(
                        isLoading = false,
                        language = settings.language,
                        selectedGroupId = settings.selectedGroupId,
                        selectedGroupName = settings.selectedGroupName,
                        subgroup = settings.subgroup,
                        scheduleView = settings.scheduleView,
                        customPeriods = periods,
                        idnp = idnp,
                        notificationSettings = notifications,
                        lastScheduleRefreshEpoch = lastRefresh
                    )
                }
            }
        }
    }

    fun loadGroups(force: Boolean = false) {
        viewModelScope.launch {
            runCatching { settingsRepository.getGroups(force) }
                .onSuccess { groups -> _uiState.update { it.copy(groups = groups, error = null) } }
                .onFailure { _uiState.update { it.copy(error = "Failed to load groups") } }
        }
    }

    fun refreshAccount() {
        viewModelScope.launch {
            val user = authRepository.getCurrentUser()
            _uiState.update {
                it.copy(
                    account = AccountUiState(
                        email = user?.email,
                        isVerified = user?.isVerified == true,
                        isAuthenticated = user != null
                    )
                )
            }
        }
    }

    fun setLanguage(language: String) {
        viewModelScope.launch { settingsRepository.setLanguage(language) }
    }

    fun selectGroup(group: GroupOption) {
        viewModelScope.launch { settingsRepository.setGroup(group.id, group.name) }
    }

    fun setSubgroup(subgroup: String) {
        viewModelScope.launch { settingsRepository.setSubgroup(subgroup) }
    }

    fun setScheduleView(view: String) {
        viewModelScope.launch { settingsRepository.setScheduleView(view) }
    }

    fun saveIdnp(idnp: String) {
        viewModelScope.launch { settingsRepository.saveIdnp(idnp.trim()) }
    }

    fun clearIdnp() {
        viewModelScope.launch { settingsRepository.clearIdnp() }
    }

    fun saveNotificationSettings(settings: NotificationSettings) {
        viewModelScope.launch { settingsRepository.setNotificationSettings(settings) }
    }

    fun addCustomPeriod(period: CustomPeriodSetting) {
        viewModelScope.launch { settingsRepository.addCustomPeriod(period) }
    }

    fun updateCustomPeriod(period: CustomPeriodSetting) {
        viewModelScope.launch { settingsRepository.updateCustomPeriod(period) }
    }

    fun deleteCustomPeriod(id: String) {
        viewModelScope.launch { settingsRepository.deleteCustomPeriod(id) }
    }

    fun refreshSchedule() {
        viewModelScope.launch {
            _uiState.update { it.copy(isRefreshingSchedule = true) }
            runCatching { settingsRepository.refreshScheduleMetadata() }
                .onFailure { _uiState.update { state -> state.copy(error = "Failed to refresh schedule") } }
            _uiState.update { it.copy(isRefreshingSchedule = false) }
        }
    }

    fun clearScheduleCache() {
        viewModelScope.launch { settingsRepository.clearScheduleCache() }
    }

    fun checkForUpdates(manual: Boolean = true) {
        viewModelScope.launch {
            _uiState.update { it.copy(isCheckingForUpdate = true, updateMessage = null) }
            val update = if (manual) {
                updateRepository.manualCheckForUpdate()
            } else {
                updateRepository.checkForUpdate(forceCheck = false)
            }

            _uiState.update {
                if (update != null) {
                    it.copy(updateInfo = update, isCheckingForUpdate = false, currentVersion = update.currentVersion)
                } else {
                    it.copy(
                        isCheckingForUpdate = false,
                        updateInfo = null,
                        currentVersion = updateRepository.getCurrentVersion(),
                        updateMessage = "You are already on ${updateRepository.getCurrentVersion()}"
                    )
                }
            }
        }
    }

    fun dismissUpdate(version: String) {
        viewModelScope.launch {
            updateRepository.dismissVersion(version)
            _uiState.update { it.copy(updateInfo = null, updateMessage = "Update reminder postponed") }
        }
    }

    fun logout() {
        authRepository.logout()
        _uiState.update { it.copy(account = AccountUiState()) }
    }

    fun deleteAccount(password: String) {
        viewModelScope.launch {
            authRepository.deleteAccount(password)
                .onSuccess {
                    _uiState.update {
                        it.copy(
                            account = AccountUiState(),
                            updateMessage = "Deletion request submitted. Check your email."
                        )
                    }
                }
                .onFailure {
                    _uiState.update { state -> state.copy(error = it.message ?: "Account deletion failed") }
                }
        }
    }

    fun resetAllSettings() {
        viewModelScope.launch { settingsRepository.resetSettingsToDefaults() }
    }
}
